<template><el-card><h3>业务意图创建</h3><el-form :inline="true" :model="form"><el-form-item label="意图名称"><el-input v-model="form.intentName"/></el-form-item><el-form-item label="源区域"><el-select v-model="form.sourceRegionId"><el-option v-for="r in regions" :label="r.name" :value="r.id"/></el-select></el-form-item><el-form-item label="源组织"><el-select v-model="form.sourceOrgId"><el-option v-for="o in orgs" :label="o.name" :value="o.id"/></el-select></el-form-item><el-form-item label="目标应用"><el-select v-model="form.targetAppId"><el-option v-for="a in apps" :label="a.name" :value="a.id"/></el-select></el-form-item><el-form-item label="访问动作"><el-select v-model="form.action"><el-option v-for="x in ['允许','拒绝','限速','审计']" :label="x" :value="x"/></el-select></el-form-item><el-form-item label="协议"><el-select v-model="form.protocol"><el-option v-for="x in ['TCP','UDP','HTTP','HTTPS','ICMP']" :label="x" :value="x"/></el-select></el-form-item><el-form-item label="端口"><el-input v-model="form.port"/></el-form-item><el-form-item label="生效时间"><el-date-picker v-model="form.effectiveTime" type="datetime"/></el-form-item><el-form-item label="优先级"><el-input-number v-model="form.priority"/></el-form-item><el-form-item label="状态"><el-select v-model="form.status"><el-option label="草稿" value="草稿"/><el-option label="启用" value="启用"/></el-select></el-form-item><el-button type="primary" @click="create">创建意图</el-button></el-form></el-card><el-card><h3>意图列表</h3><el-table :data="intents" border><el-table-column prop="intentName" label="意图名称"/><el-table-column prop="action" label="动作"/><el-table-column prop="protocol" label="协议"/><el-table-column prop="port" label="端口"/><el-table-column prop="priority" label="优先级"/><el-table-column label="操作"><template #default="s"><el-button type="success" @click="gen(s.row.id)">生成策略</el-button><el-button type="danger" @click="delIntent(s.row.id)">删除</el-button></template></el-table-column></el-table></el-card><el-card><h3>策略预览与管理</h3><el-table :data="policies" border><el-table-column prop="name" label="策略名称"/><el-table-column prop="rule" label="策略规则"/><el-table-column prop="status" label="状态"/><el-table-column prop="conflict" label="冲突"><template #default="s"><el-tag :type="s.row.conflict?'danger':'success'">{{s.row.conflict?'冲突':'正常'}}</el-tag></template></el-table-column><el-table-column label="操作"><template #default="s"><el-button @click="status(s.row,'启用')">启用</el-button><el-button @click="status(s.row,'停用')">停用</el-button><el-button type="danger" @click="delPolicy(s.row.id)">删除</el-button></template></el-table-column></el-table></el-card></template>
<script setup>import{ref,onMounted}from'vue';import{ElMessage}from'element-plus';import{api}from'../api/http';const user=JSON.parse(localStorage.getItem('user')),regions=ref([]),orgs=ref([]),apps=ref([]),intents=ref([]),policies=ref([]);const form=ref({action:'允许',protocol:'TCP',port:'443',priority:10,status:'草稿'});async function load(){regions.value=(await api.get('/regions')).data;orgs.value=(await api.get('/orgs')).data;apps.value=(await api.get('/apps')).data;intents.value=(await api.get('/intents')).data;policies.value=(await api.get('/policies')).data}async function create(){let sr=regions.value.find(x=>x.id===form.value.sourceRegionId),so=orgs.value.find(x=>x.id===form.value.sourceOrgId),ta=apps.value.find(x=>x.id===form.value.targetAppId);await api.post('/intents',{...form.value,sourceRegionName:sr?.name,sourceOrgName:so?.name,targetAppName:ta?.name,username:user.username});form.value={action:'允许',protocol:'TCP',port:'443',priority:10,status:'草稿'};load()}async function gen(id){const r=await api.post('/intents/'+id+'/generate',{username:user.username});ElMessage[r.data.conflict?'warning':'success'](r.data.conflict?'生成成功，但检测到策略冲突':'策略生成成功');load()}async function status(p,s){await api.patch('/policies/'+p.id+'/status',{status:s,username:user.username});load()}async function delIntent(id){await api.delete('/intents/'+id,{params:{username:user.username}});load()}async function delPolicy(id){await api.delete('/policies/'+id,{params:{username:user.username}});load()}onMounted(load)</script>
